import os
import json
import time
from pathlib import Path

class APICache:
    def __init__(self, cache_dir='cache', expiration_time=3600):
        self.cache_dir = Path(cache_dir)
        self.expiration_time = expiration_time
        self.cache_dir.mkdir(exist_ok=True)

    def _get_cache_file_path(self, key):
        return self.cache_dir / f"{key}.json"

    def _is_cache_valid(self, cache_file):
        return time.time() - cache_file.stat().st_mtime < self.expiration_time

    def get(self, key):
        cache_file = self._get_cache_file_path(key)
        if cache_file.exists() and self._is_cache_valid(cache_file):
            with open(cache_file, 'r') as f:
                return json.load(f)
        return None

    def set(self, key, data):
        cache_file = self._get_cache_file_path(key)
        with open(cache_file, 'w') as f:
            json.dump(data, f)

    def clear(self):
        for cache_file in self.cache_dir.glob('*.json'):
            cache_file.unlink()

